var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"POLICE_EXTRA_NULL_NULL","text":{"KOREA":"경정님? 폴른 호크라는 데에서 편지가 왔던데……","JPN":"警視？　フォーレン・ホークというところから手紙が来ていますが……","ENG":"Major? You received a letter from a place called \\"Fallen Hawk\\"...","TWN":"警正？收到一個叫作墮落之鷹的地方來信……"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"POLICE_EXTRA_NULL_NULL","text":{"KOREA":"뭐야? 현장 나가셨나? 경위님도 안 계시네.","JPN":"あれ？　現場かな？　警部補もいない。","ENG":"Huh? I guess she's out? I don't see the lieutenant either.","TWN":"人呢？去現場啦？姜警官也不在？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"POLICE_EXTRA_NULL_NULL","text":{"KOREA":"책상 위에다 놓고 가야 하나…… 이거 괜히 또 한소리 듣는 거 아닌가 몰라.","JPN":"机の上においていくか……？　また怒られるかもしれないしな。","ENG":"Do I just leave it on her desk? I don't want to get another earful from her...","TWN":"要放在桌子上嗎……不知道會不會又惹罵？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>간만에 인사드리는군요, 형사님. 의뢰하셨던 실종자 탐색에 대해 전해 드릴 소식이 있습니다.</color>","JPN":"<color=#ffd34c>ご無沙汰しております、刑事さん。依頼してくださった失踪者の探索についてお知らせすることがあります。</color>","ENG":"<color=#ffd34c>Hello, Detective. Many moons have passed since we last talked. I am writing this letter to update you about the search for the missing person that you requested.</color>","TWN":"<color=#ffd34c>警官，好久不見。關於之前您委託尋找失蹤人士一事，有消息要告訴您。</color>"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>결론부터 말씀드리죠. 언니 분은 찾았지만 형사님과 만나길 원치 않으시더군요.</color>","JPN":"<color=#ffd34c>結論からお話いたしましょう。お姉さんは見つかりましたが、刑事さんとは会いたくないとおっしゃっていました。</color>","ENG":"<color=#ffd34c>Regarding your sister, I have found her, but it seems that she does not want to meet with you.</color>","TWN":"<color=#ffd34c>先說結論吧，我已經找到您的姊姊，但她不想見您。</color>"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그래서 대신 서신을 받아 왔습니다. 동봉해 두었으니 확인해 보시죠.</color>","JPN":"<color=#ffd34c>それで代わりに手紙をもらってきました。同封しましたのでご確認を。</color>","ENG":"<color=#ffd34c>So instead, I received a letter. I have enclosed the letter as well, so that you can read it.</color>","TWN":"<color=#ffd34c>不過她有寫封信給您，信已經隨此信附上，請您查閱。</color>"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>혹여 다른 의뢰가 있으시면 언제든 연락 주시길.</color>","JPN":"<color=#ffd34c>もし他にご依頼がございましたら、いつでもご連絡ください。</color>","ENG":"<color=#ffd34c>If there is anything else I can do for you, please contact me at your earliest convenience.</color>","TWN":"<color=#ffd34c>若有其他委託，請隨時聯繫我。</color>"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"유치원 이후로 처음 쓰는 편지인데 너한테 잘 전해질지 모르겠네.","JPN":"幼稚園以来、初めて手紙を書くけどちゃんと伝わるかな。","ENG":"I haven't written a letter since I was in kindergarten. I hope this reaches you, though.","TWN":"自從幼稚園後，這還是我第一次寫信，不知道能不能順利交到你手裡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"어쩌면 이 편지가 가짜라고 의심할지도 모르겠어.","JPN":"もしかしたらこの手紙は偽物だと疑うかもしれないね。","ENG":"Or maybe, you suspect that this letter is fake.","TWN":"說不定你會懷疑這封信是假的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 이것만은 장담할게. 나는 네가 믿는 대로 멀쩡하게 살아 있어.","JPN":"でもこれだけは確かだよ。私はあなたが信じてるとおり、ちゃんと生きてる。","ENG":"But let me assure you. I'm alive and well.","TWN":"不過唯獨這件事我可以保證，就是我還活得好好的，正如你所相信的那樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이유리, 기회는 지금뿐이다. 어서 여길 빠져나가.","JPN":"カスカベ、チャンスは今しかない。早くここから脱出しろ。","ENG":"Yuri. Now's your chance. Get out of here, now!","TWN":"李悠麗，趁現在，快離開這裡。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"뭐? 대장은 그 상태로 뭘 어쩌려고?","JPN":"は？　隊長はその身体でどうするつもりだ？","ENG":"What? Then what about you?","TWN":"什麼？隊長你傷得那麼重還想做什麼？"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"할일은 마치고 가야지. 처음 얘기했던 집결지에서 보자.","JPN":"仕事は終えないとな。最初に話した集結地で会おう。","ENG":"Someone's gotta finish the job. I'll meet you back at the rendezvous point.","TWN":"當然是做完該做的事再走，我們在一開始說好的集合地點見！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"……알겠어, 대장. 기다리고 있을게.","JPN":"……わかった、隊長。待ってるから。","ENG":"...Okay, Captain. I'll be waiting for you.","TWN":"……好，隊長，我等你。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"윽……! 기다려!","JPN":"うっ……！　ちょっと！","ENG":"Ngh...! Hold it!","TWN":"唔……！等等！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":" 누구 맘대로 도망치겠다는 거야?!","JPN":" 何を勝手に逃げてるの！？","ENG":"  Where do you think you're going?!","TWN":" 誰准你逃走的？！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"고마워, 이유미 경정. 네 덕분에 확실해졌어.","JPN":"ありがとう、カスカベ・ユミ警視。おかげで確信できた。","ENG":"Thank you, Major Lee Yumi. Everything's crystal clear, all thanks to you.","TWN":"謝謝你，李悠美警正。托你的福，讓我確定一件事。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"나는 죽기 전까지 민병대를 그만둘 생각 없어.","JPN":"私は死ぬまで民兵隊をやめる気はない。","ENG":"You see, I have no intention of quitting the Militia until I die.","TWN":"就是在我死之前，都不會放棄民兵隊。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"너는 우리가 잘못됐다고 말하지만, 아직은 우리를 필요로 하는 사람들도 많아.","JPN":"警視は私たちが間違えていると言うけど、まだ私たちを必要としている人たちも多い。","ENG":"You say that we're the bad guys but still, there are people who need our help.","TWN":"雖然你說我們做的事是不對的，但還有很多人需要我們。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"현장에 있는 너라면 더 잘 알고 있을 거야. ","JPN":"現場にいるんだからよくわかってるはずだろ。 ","ENG":"You've been out on the field, so I'm sure you know what I'm talking about. ","TWN":"在第一線奔走的你應該比我更清楚，"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"세상엔 법이 닿지 않고, 법을 짓밟는 범죄자들도 존재한다는 걸.","JPN":"世界には法が届かず、法を踏みにじる犯罪者も存在しているってこと。","ENG":"That there are criminals the law can't touch, and even those who think they are above it.","TWN":"這世上有很多法律無法管束的灰暗地帶，也有很多踐踏法律的罪犯。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그러니까…… 만약 한 번 더 내가 괴물이 될 때는, 네가 붙잡아 줘.","JPN":"だから……もし私がもう一度化け物になった時には、また捕まえてくれ。","ENG":"So... If I become a monster again, I want you to stop me.","TWN":"所以……萬一我再次變成怪物，請你逮補我。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"흥……! 한 번 더?! 지금 당장 붙잡아 주겠어!","JPN":"ふん……！　もう一度！？　今すぐ捕まえてやるわ！","ENG":"Hmph...! Again?! I'll stop you right now!","TWN":"哼……！什麼再次？！我現在就要立刻逮補你！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그 몸상태로는 어려울걸. 먼저 간다.","JPN":"その身体では無理だろう。先に行く。","ENG":"That's going to be hard in your current state. Anyway, bye.","TWN":"以你現在的身體狀況恐怕沒辦法，我先告辭。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"거기 서지 못해!! 멈춰!","JPN":"待ちなさい！！　止まれ！","ENG":"Stop right there!! STOP!","TWN":"你給我站住！！站住！"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"경찰이 됐더라. 테라사이드 전역이라는 데에서도 엄청 활약했다면서?","JPN":"警察官になったみたいだね。テラサイド戦域というところでたくさん活躍したんだって？","ENG":"I heard you became a cop. And you participated in the Terraside battles.","TWN":"我聽說你成為一名警察，在整個特拉賽德地區都很活躍？"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"대단하고, 칭찬해 줘야 할 텐데…… 역시 걱정부터 들더라.","JPN":"偉いし、褒めてあげないといけないのに……やっぱり心配になる。","ENG":"I know I'm supposed to congratulate you... But it got me worried at first.","TWN":"我應該誇獎你很棒才對……可是我反而先擔心起來。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"narration","speaker":null,"text":{"KOREA":"카운터도 안 다치는 건 아니니까 조심해. 모르는 건 다른 경찰 분들에게도 꼬박꼬박 물어 보고.","JPN":"カウンターだからって怪我しないわけじゃないから気をつけて。知らないことがあったら他の警察の方にちゃんと聞くこと。","ENG":"Be careful. Counters aren't invincible, you know. And if there's anything you don't know, be sure to ask the other officers.","TWN":"制裁者又不是不會受傷，你要小心點。有什麼不懂的，就多向其他警官請教。"},"stage":{"bg":"SKYLINE_NIGHT2","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"움직이지 마! 총 내려 놓고 손 들어!","JPN":"動くな！　銃を下ろして手を上げろ！","ENG":"Freeze! Put the gun on the ground and your hands above your head!","TWN":"不許動！放下槍，把手舉起來！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L44_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"본부, 여기는 선발 진입대! 거수자 확보했습니다!","JPN":"本部、こちら先発進入隊！　挙動不審者を確保しました！","ENG":"HQ! This is team alpha! We've secured an armed suspect!","TWN":"總部，這裡是先發部隊！已經抓到可疑人士！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L46_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"…… 저항할 생각 없소. 체포하시오.","JPN":"……抵抗する気はない。逮捕してくれ。","ENG":"...I surrender. Arrest me.","TWN":"……我不打算抵抗，逮捕我吧。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그러려고 남았으니까.","JPN":"そうするために残ったんだ。","ENG":"That's why I stayed.","TWN":"不然你以為我會乖乖待在這裡嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"너 혼자 풀기 힘들 고민도 많이 있을 거야.","JPN":"あなた一人では解決できない悩みも多いはずよ。","ENG":"I'm sure you have a lot of concerns that you can't solve on your own.","TWN":"你會遇到很多一個人無法解決的難題。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"그럴 때는 부담 갖지 말고 옆에 있는 사람들에게 의지해.","JPN":"そういう時には難しく考えないで、隣にいる人たちに頼りなさい。","ENG":"When that happens, try to rely on those around you.","TWN":"那時候不要覺得有壓力，要依靠身邊的人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"나도 후임이 한 명 생겼어. 밝고 붙임성도 밝아서 고생할 때도 힘이 되더라.","JPN":"私にも後輩が一人できたんだ。明るくて人当たりがいいから、苦労してる時にも力になってくれる。","ENG":"A rookie joined my team too. She's always cheerful and friendly, which helps when I'm having a bad day.","TWN":"我現在也有一個後輩，她很開朗、活潑，在我覺得累的時候，也會成為我的力量。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"메이드장니임!!","JPN":"メイド長ぉぉ！！","ENG":"Chief Maid!!","TWN":"女僕長！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L7_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"야, 환자한테 매달리지 마! 그러다 덧나면 어쩌려고!","JPN":"ちょっと、患者にすがらない！　傷がこじれたらどうするのよ！","ENG":"Hey, stop that! Can't you see she's hurt?! What if her wounds don't heal correctly because of you?!","TWN":"喂，別纏著病患！萬一傷口惡化怎麼辦！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"모두에게 걱정을 끼쳤네요…… 메이드장으로서는 최악이에요.","JPN":"皆さんには心配をかけましたね……メイド長としては最悪です。","ENG":"It seems I've only caused worry for everyone... I feel as if I have failed as Chief Maid.","TWN":"讓大家擔心了……身為女僕長，真是不好的示範。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"모네에게 들었습니다. 다음부터 고민이 있을 때는 편하게 말씀해 주세요.","JPN":"モネから聞きました。次からは悩みがある時、遠慮なく話してください。","ENG":"We heard about everything from Mone. Please feel free to talk to us if you have any concerns from now on.","TWN":"我聽莫妮說了，下次有什麼煩惱，請儘管說出來。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L13_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저에게 손을 내밀어 주셨던 것처럼, 저도 메이드장님을 잡아드릴 수 있도록 분발할 테니까요.","JPN":"私に手を差し伸べてくださったように、私もメイド長を支えられるように頑張りますので。","ENG":"Just as you reached out to me, I'll do my best to hold on to you, Chief Maid.","TWN":"女僕長曾經對我伸出援手，我也一定會努力抓住女僕長的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"……고마워요, 릴리.","JPN":"……ありがとうございます、リリー。","ENG":"...Thank you, Lily.","TWN":"……謝謝你，莉莉。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"힘들 때 곁에 있어 주지 못해서 미안해.","JPN":"辛い時に一緒にいてあげられなくてごめん。","ENG":"I'm sorry I couldn't be with you through your hardships.","TWN":"對不起，在你辛苦的時候沒能陪在你身邊。"},"stage":{"bg":"SS_MILITIA_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"그래도 이것만큼은 알아 줘. 유미야.","JPN":"でもこれだけはわかってほしいんだ、ユミ。","ENG":"But Yumi, please know this.","TWN":"不過悠美，有件事你要知道，"},"stage":{"bg":"SS_MILITIA_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"나는 항상 널 지켜보고 있을 거야.","JPN":"私はいつもあなたを見守っているよ。","ENG":"I'm always watching over you.","TWN":"就是我會一直守護著你。"},"stage":{"bg":"SS_MILITIA_03","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"경위, 오늘은 내가 조금 일찍 왔지?","JPN":"警部補、今日はちょっと早く来たわ。","ENG":"I came a little early today, didn't I, Lieutenant?","TWN":"姜素英員警，我今天是不是來得有點早？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"경찰청 사람들이 과일을 보내 줬어.","JPN":"警察庁の人たちが果物を送ってくれたの。","ENG":"The people at the station asked me to give this get-well-soon gift basket to you.","TWN":"警察局的人有送水果來喔。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"차 수리비 대신이라고 토를 단 걸 보면, 경위가 계속 병실에 있길 바라는 것 같다니까.","JPN":"車の修理代の代わりだって言ってるし、警部補がずっと病室にいてほしいみたいなんだよね。","ENG":"I can't shake the feeling that they want you to stay here, given that they said this was the money they were going to use for car repairs.","TWN":"他們說就當作是修車費，根本是想你一直待在病房裡吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그 날 이후로 얼마나 지났는데, 다들 경위면 멀쩡히 일어날 거라고……","JPN":"あの日以来結構経つけど、みんな警部補ならきっと起き上がるって……","ENG":"It's been days since the incident, and everyone told me that you were going to be just fine...","TWN":"從那天之後都過多久啦？大家都說你一定會平安醒來……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……경위? 어디 갔지? 내가 병실을 잘못 찾았나?","JPN":"……警部補？　どこ行ったの？　病室を間違えたかな？","ENG":"...Lieutenant? Where did she go? Am I in the wrong room?","TWN":"……姜素英員警？人呢？是我走錯病房嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"오늘 중으로는 꼭 말씀드리시죠. 회장님도 수술을 지원해 주신 뒤로 좋은 소식을 기다리고 계시니까요.","JPN":"今日中には必ず話してさしあげてください。会長も手術を援助されて、いい知らせをお待ちなので。","ENG":"You should tell her today. Our president is also waiting for good news ever since she funded the operation.","TWN":"今天一定要說，會長協助手術之後，也一直在等好消息呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"아하하, 역시 그렇죠. 아무리 그래도 혼수 상태인 척은 하루밖에 못 하겠더라고요.","JPN":"あはは、やっぱりそうですよね。いくらなんでも昏睡状態のふりは一日しかできなくて。","ENG":"A ha ha, I'm sure she is. But still, it was so hard pretending to be in a coma for even a day.","TWN":"哈哈哈，是吧？要我假裝昏迷，最多只能撐一天啦。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"회장님께는 감사하다고 좀 전해 주세요. 경찰로서 이런 걸 받아도 되나 싶긴 한데……","JPN":"会長には感謝してますって伝えてください。警察官がこんなものもらってもいいのかって気もするんですが……","ENG":"Please tell her that I said thank you. But as a police officer, I'm not sure if I can accept something like this...","TWN":"請代為向會長轉達我的感謝，身為警察能接受這……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"……경위.","JPN":"……警部補。","ENG":"...Lieutenant.","TWN":"……姜素英員警。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위!! 당장 이리 안 와!!","JPN":"マエカワ・ナツミ警部補！！　今すぐこっち来なさい！！","ENG":"Lieutenant Kang Soyoung!! Report to me right now!!","TWN":"姜素英員警！！你馬上給我過來！！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"추신.","JPN":"追伸。","ENG":"PS.","TWN":"最後，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"경찰 완장, 정말 잘 어울리더라.","JPN":"警察の腕章、とても似合ってたよ。","ENG":"That police armband of yours. It looks good on you.","TWN":"警察的臂章真的很適合你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};